import{c as n,Q as t,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"prompt / context / agent / harness: ボトルネック移動で読むLLM engineeringの系譜とその先","description":"","frontmatter":{"url":"https://zenn.dev/biscuit/articles/llm-engineering-layers-bottleneck-shift","title":"prompt / context / agent / harness: ボトルネック移動で読むLLM engineeringの系譜とその先","author":"biscuit","archived":"2026-05-27T00:00:00.000Z","domain":"zenn.dev","published":"2026-05-24T00:00:00.000Z","tags":["llm","prompt-engineering","context-engineering","agent-engineering","harness-engineering","bottleneck","eval","governance"],"word_count":"約 2,500 字"},"headers":[],"relativePath":"research/ai-articles/2026-05-24-biscuit-llm-engineering-bottleneck-shift.md","filePath":"research/ai-articles/2026-05-24-biscuit-llm-engineering-bottleneck-shift.md","lastUpdated":1779901665000}'),i={name:"research/ai-articles/2026-05-24-biscuit-llm-engineering-bottleneck-shift.md"};function o(l,e,s,g,h,c){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="prompt-context-agent-harness-ボトルネック移動で読むllm-engineeringの系譜とその先" tabindex="-1">prompt / context / agent / harness: ボトルネック移動で読むLLM engineeringの系譜とその先 <a class="header-anchor" href="#prompt-context-agent-harness-ボトルネック移動で読むllm-engineeringの系譜とその先" aria-label="Permalink to &quot;prompt / context / agent / harness: ボトルネック移動で読むLLM engineeringの系譜とその先&quot;">​</a></h1><blockquote><p><strong>來源</strong>：<a href="https://zenn.dev/biscuit/articles/llm-engineering-layers-bottleneck-shift" target="_blank" rel="noreferrer">zenn.dev</a><strong>作者</strong>：biscuit <strong>發布日期</strong>：2026-05-24（更新：2026-05-25） <strong>收錄日期</strong>：2026-05-27</p></blockquote><hr><h2 id="overview-概要" tabindex="-1">Overview / 概要 <a class="header-anchor" href="#overview-概要" aria-label="Permalink to &quot;Overview / 概要&quot;">​</a></h2><p>LLM と周辺技術の成熟に伴い、技術的ボトルネックはモデル本体から外側へと順次移動してきた。prompt → context → agent → harness という4つの工学レイヤーは互いを「置き換える」トレンドではなく、累積的なアーキテクチャとして積み重なっている。著者は次のボトルネックとして eval と governance を予測する。</p><p><strong>核心主張</strong>：「LLM と周辺技術の成熟に伴い、ボトルネックはLLM本体から外側へと移動する。」</p><hr><h2 id="_4つのエンジニアリングレイヤー" tabindex="-1">4つのエンジニアリングレイヤー <a class="header-anchor" href="#_4つのエンジニアリングレイヤー" aria-label="Permalink to &quot;4つのエンジニアリングレイヤー&quot;">​</a></h2><table tabindex="0"><thead><tr><th>レイヤー</th><th>ボトルネック</th><th>主要技術</th></tr></thead><tbody><tr><td><strong>Prompt</strong></td><td>入力の最適化</td><td>Few-shot learning、Chain-of-Thought</td></tr><tr><td><strong>Context</strong></td><td>情報のキュレーション</td><td>RAG、token compaction、sub-agent isolation</td></tr><tr><td><strong>Agent</strong></td><td>推論ループ設計</td><td>ReAct、ツールオーケストレーション、マルチエージェント</td></tr><tr><td><strong>Harness</strong></td><td>実行環境</td><td>サンドボックス、スケジューリング、制御機構</td></tr></tbody></table><hr><h2 id="prompt-engineering-時代" tabindex="-1">Prompt Engineering 時代 <a class="header-anchor" href="#prompt-engineering-時代" aria-label="Permalink to &quot;Prompt Engineering 時代&quot;">​</a></h2><p>モデルへの入力を精巧に調整することがボトルネックだった時代。Few-shot learning や Chain-of-Thought（CoT）などのテクニックが中心。</p><p>しかし「Prompting Inversion」（Imran Khan, arXiv:2510.22251）が示すように、推論モデルの進化によりプロンプトテクニックの効果は逆転しうる。制約プロンプトが中位モデルでは有効でも、高度なモデルでは「hyper-literalism」を誘発して性能を下げる。最適なプロンプト戦略はモデル能力と共進化する必要がある。</p><hr><h2 id="context-engineering-時代" tabindex="-1">Context Engineering 時代 <a class="header-anchor" href="#context-engineering-時代" aria-label="Permalink to &quot;Context Engineering 時代&quot;">​</a></h2><p>コンテキストウィンドウの拡大だけでは品質は保証されないことが明らかになった時代。</p><p>Microsoft-Salesforce の研究（Laban et al., arXiv:2505.06120）によれば、マルチターン会話では6つの生成タスクで平均39%のパフォーマンス低下が確認された。トークン上限が拡大しても文脈管理の質がボトルネックになる。RAG、token compaction、sub-agent isolation などのテクニックがこの課題に対応する。</p><hr><h2 id="agent-engineering-時代" tabindex="-1">Agent Engineering 時代 <a class="header-anchor" href="#agent-engineering-時代" aria-label="Permalink to &quot;Agent Engineering 時代&quot;">​</a></h2><p>自律的な推論ループ設計にボトルネックが移動した時代。ReAct フレームワークが observe-think-act サイクルを定式化し、プラットフォーム API がツールインテグレーションを標準化した。マルチエージェントシステムの台頭もこの時期に重なる。</p><hr><h2 id="harness-engineering-時代" tabindex="-1">Harness Engineering 時代 <a class="header-anchor" href="#harness-engineering-時代" aria-label="Permalink to &quot;Harness Engineering 時代&quot;">​</a></h2><p>エージェントの実行インフラを抽象化することがボトルネックとなった現在。</p><p>Philipp Schmid のアナロジーでは、harness は「OS」、agents は「applications」として位置づけられる。Harvey AI の事例では、モデルを変更せずにharness側だけの修正で「実質的な精度改善」を達成した。</p><p>Harness は以下を担う：</p><ul><li>サンドボックス化されたコード実行</li><li>ツール呼び出しのスケジューリングと制御</li><li>セキュリティ境界の設定</li><li>エージェント間通信の管理</li></ul><hr><h2 id="次のフロンティア-eval-と-governance" tabindex="-1">次のフロンティア：Eval と Governance <a class="header-anchor" href="#次のフロンティア-eval-と-governance" aria-label="Permalink to &quot;次のフロンティア：Eval と Governance&quot;">​</a></h2><h3 id="eval-レイヤー" tabindex="-1">Eval レイヤー <a class="header-anchor" href="#eval-レイヤー" aria-label="Permalink to &quot;Eval レイヤー&quot;">​</a></h3><p>生成システムの出力品質を定義することが次のボトルネックとなる。従来のMLメトリクスを超えたドメイン固有の基準が必要。Galileo は eval を CI/CD に統合するアプローチを推進し、AWS などは評価をオブザーバビリティフレームワークに組み込む。</p><h3 id="governance-レイヤー" tabindex="-1">Governance レイヤー <a class="header-anchor" href="#governance-レイヤー" aria-label="Permalink to &quot;Governance レイヤー&quot;">​</a></h3><p>エージェント間（A2A）通信の可視性が極めて不十分。「A2A 通信を完全に把握している組織はわずか24.4%」（Gravitee, State of AI Agent Security 2026）。</p><p>整備されつつある標準：</p><ul><li><strong>MCP Authorization</strong>：OAuth 2.1ベース</li><li><strong>SPIFFE</strong>：エージェントアイデンティティフレームワーク</li><li><strong>NIST Agent Interoperability Profile</strong>：2026年Q4予定</li></ul><hr><h2 id="規制環境" tabindex="-1">規制環境 <a class="header-anchor" href="#規制環境" aria-label="Permalink to &quot;規制環境&quot;">​</a></h2><ul><li><strong>EU AI Act</strong>：2026年8月から施行開始</li><li><strong>NIST AI Agent Standards Initiative</strong>：アイデンティティ・権限・アクション・監査証跡の4次元でガバナンスを正式化する取り組み（2026年2月発表）</li></ul><hr><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><p>4つのエンジニアリングレイヤー（prompt / context / agent / harness）はそれぞれ独立した「トレンド」ではなく、ボトルネックの移動を反映した累積的な構造として理解すべきである。そして現在、eval と governance が次のボトルネックとして台頭しつつある。</p>',40)])])}const u=n(i,[["render",o]]);export{p as __pageData,u as default};
